```typescript
export type Graph<T> = Map<T, T[]>;

export function toposort<T>(graph: Graph<T>): T[] {
  if (!graph || graph.size === 0) {
    return [];
  }

  const visited = new Set<T>();
  const recursionStack = new Set<T>();
  const sorted: T[] = [];

  const dfs = (node: T): void => {
    visited.add(node);
    recursionStack.add(node);

    const neighbors = graph.get(node);
    if (neighbors) {
      for (const neighbor of neighbors) {
        if (recursionStack.has(neighbor)) {
          throw new Error(`Cycle detected: ${String(neighbor)} is in recursion stack`);
        }
        if (!visited.has(neighbor)) {
          dfs(neighbor);
        }
      }
    }

    recursionStack.delete(node);
    sorted.push(node);
  };

  for (const node of graph.keys()) {
    if (!visited.has(node)) {
      dfs(node);
    }
  }

  return sorted.reverse();
}

export function detectCycle<T>(graph: Graph<T>): boolean {
  if (!graph || graph.size === 0) {
    return false;
  }

  const visited = new Set<T>();
  const recursionStack = new Set<T>();

  const hasCycle = (node: T): boolean => {
    visited.add(node);
    recursionStack.add(node);

    const neighbors = graph.get(node);
    if (neighbors) {
      for (const neighbor of neighbors) {
        if (recursionStack.has(neighbor)) {
          return true;
        }
        if (!visited.has(neighbor)) {
          if (hasCycle(neighbor)) {
            return true;
          }
        }
      }
    }

    recursionStack.delete(node);
    return false;
  };

  for (const node of graph.keys()) {
    if (!visited.has(node)) {
      if (hasCycle(node)) {
        return true;
      }
    }
  }

  return false;
}
```

**Critique - 3 Potential Bugs:**

1. **Bug: Graph with isolated nodes** - Nodes with no outgoing edges that aren't keys in the graph won't be processed. **Fix:** Already handled since we only iterate graph.keys().

2. **Bug: Missing null check in dfs** - If graph.get(node) returns undefined, we skip gracefully, but neighbors could be sparse. **Fix:** Added `if (neighbors)` check ensures undefined arrays don't cause errors.

3. **Bug: Dangling edge targets** - If an edge points to a node not in graph.keys(), it won't be included in output. **Fix:** Graph must be well-formed with all nodes as keys; dangling references are invalid input (caller responsibility).

